// Build lookup index pro O(1) access
const I18N_LOOKUP = new Map();
for (const [cs, en, es] of I18N_PHRASES) {
  I18N_LOOKUP.set(cs, { en, es });
}

// Skip tagy + class patterns (data, kód, monospace)
const I18N_SKIP_TAGS = new Set(['CODE', 'PRE', 'KBD', 'SCRIPT', 'STYLE', 'INPUT', 'TEXTAREA', 'SELECT', 'OPTION']);

function shouldSkipNode(node) {
  let el = node.parentElement;
  while (el) {
    if (I18N_SKIP_TAGS.has(el.tagName)) return true;
    if (el.dataset && el.dataset.noTranslate !== undefined) return true;
    if (el.contentEditable === 'true') return true;
    // Skip monospace fonty (CSS .lic-key, monospace)
    if (el.classList && (
      el.classList.contains('lic-key') ||
      el.classList.contains('mono') ||
      el.classList.contains('cmdk-hint')
    )) return true;
    el = el.parentElement;
  }
  return false;
}

// Translate one text node
function translateTextNode(node) {
  if (shouldSkipNode(node)) return;
  const raw = node.nodeValue;
  if (!raw || raw.length < 2 || raw.length > 500) return;
  const trimmed = raw.trim();
  if (!trimmed) return;

  // Lookup přesnou shodu
  const entry = I18N_LOOKUP.get(trimmed);
  if (!entry) return;

  const tgt = entry[window.appekCurrentLang || 'cs'];
  if (!tgt) return;

  // Zachovej leading/trailing whitespace
  const leading  = raw.match(/^\s*/)[0];
  const trailing = raw.match(/\s*$/)[0];
  node.nodeValue = leading + tgt + trailing;
}

// Walk DOM and translate text nodes
window.translatePage = function(root) {
  if (!window.appekCurrentLang || window.appekCurrentLang === 'cs') return;
  root = root || document.body;
  const walker = document.createTreeWalker(root, NodeFilter.SHOW_TEXT, null);
  let n;
  const toTranslate = [];
  while ((n = walker.nextNode())) {
    if (n.nodeValue && n.nodeValue.trim()) toTranslate.push(n);
  }
  toTranslate.forEach(translateTextNode);
};

// Hook: po každém renderu admin.js (delegovaně přes MutationObserver na #content)
window.__appekI18nObserverInited = false;
function initI18nObserver() {
  if (window.__appekI18nObserverInited) return;
  window.__appekI18nObserverInited = true;
  const content = document.getElementById('content');
  const modal = document.getElementById('modal');
  const observer = new MutationObserver((mutations) => {
    if (window.appekCurrentLang === 'cs') return;
    for (const m of mutations) {
      m.addedNodes.forEach(n => {
        if (n.nodeType === 1) window.translatePage(n);
      });
    }
  });
  if (content) observer.observe(content, { childList: true, subtree: true });
  if (modal)   observer.observe(modal,   { childList: true, subtree: true });
}

// Init až po DOM ready
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', initI18nObserver);
} else {
  initI18nObserver();
}

// 🌍 v2.9.29 — Bulletproof lang switch:
//   1) Reverse lookup map (každý cizí jazyk → cs) — pro switch z EN/SK/DE/ES zpět
//   2) Po změně jazyka: nejdřív restore-to-cs pass, pak translate na cílový jazyk
//   3) Re-render aktuální stránky pokud existuje navigate()/renderXxx (pro dynamický obsah)
const I18N_REVERSE_LOOKUP = (function() {
  const rev = new Map();
  try {
    for (const [cs, en, es] of I18N_PHRASES) {
      if (en && en !== cs) rev.set(en, cs);
      if (es && es !== cs) rev.set(es, cs);
    }
    // Doplň SK + DE z I18N_EXTRA (pokud existuje)
    if (window.I18N_EXTRA && typeof window.I18N_EXTRA === 'object') {
      for (const cs in window.I18N_EXTRA) {
        const o = window.I18N_EXTRA[cs];
        if (o.sk && o.sk !== cs) rev.set(o.sk, cs);
        if (o.de && o.de !== cs) rev.set(o.de, cs);
        // EN a ES už máme z I18N_PHRASES, ale doplň pokud chybí
        if (o.en && o.en !== cs && !rev.has(o.en)) rev.set(o.en, cs);
        if (o.es && o.es !== cs && !rev.has(o.es)) rev.set(o.es, cs);
      }
    }
  } catch (e) {}
  return rev;
})();

// Restore one text node ke kanonickému CS textu
function restoreTextNodeToCS(node) {
  if (shouldSkipNode(node)) return;
  const raw = node.nodeValue;
  if (!raw || raw.length < 2 || raw.length > 500) return;
  const trimmed = raw.trim();
  if (!trimmed) return;
  const cs = I18N_REVERSE_LOOKUP.get(trimmed);
  if (!cs) return;
  const leading  = raw.match(/^\s*/)[0];
  const trailing = raw.match(/\s*$/)[0];
  node.nodeValue = leading + cs + trailing;
}

// Restore the whole DOM zpět do CS (pro switch out of EN/SK/DE/ES)
window.restorePageToCS = function(root) {
  root = root || document.body;
  const walker = document.createTreeWalker(root, NodeFilter.SHOW_TEXT, null);
  let n;
  const nodes = [];
  while ((n = walker.nextNode())) {
    if (n.nodeValue && n.nodeValue.trim()) nodes.push(n);
  }
  nodes.forEach(restoreTextNodeToCS);
};

// Při změně jazyka — restore-to-cs → re-render → translate (v2.9.58 fix)
// Bug před tím: kontrolovalo state.currentPage (neexistuje — admin.js má state.current),
// a translatePage běžel PŘED re-renderem → nový obsah zůstal ve staré řeči.
const _originalSetAppekLang = window.setAppekLang;
window.setAppekLang = function(code) {
  // 1) DOM zpět do CS (řeší switch z EN/SK/DE/ES na cokoliv)
  window.restorePageToCS(document.body);
  // 2) Update language state (localStorage + appekCurrentLang)
  if (_originalSetAppekLang) _originalSetAppekLang(code);

  // 3) Re-render aktuální dynamické stránky NEJDŘÍV (čerstvý CS markup)
  var didRerender = false;
  try {
    var page = (window.state && window.state.current) ? window.state.current : null;
    var appVisible = document.getElementById('app') &&
                     document.getElementById('app').style.display !== 'none';
    if (typeof window.navigate === 'function' && page && appVisible) {
      window.navigate(page);
      didRerender = true;
    }
  } catch (e) { console.warn('[i18n] re-render failed:', e); }

  // 4) AŽ POTOM přelož celý DOM do cílového jazyka (na čerstvý markup)
  //    Delší delay pokud byl re-render (navigate je async — vykreslí obsah později)
  if (code !== 'cs') {
    setTimeout(function() {
      window.translatePage(document.body);
    }, didRerender ? 250 : 40);
    // Druhý pass — pojistka pro pomalu rendrované komponenty
    setTimeout(function() {
      window.translatePage(document.body);
    }, didRerender ? 700 : 200);
  }

  // 5) Sync vlajka/kód v topbar triggeru (pro jistotu)
  setTimeout(function() {
    try {
      if (typeof window.adminPickLang === 'function' && window.ADM_LANG_META) {
        var meta = window.ADM_LANG_META[code];
        var flag = document.getElementById('adm-lang-flag');
        var codeEl = document.getElementById('adm-lang-code');
        if (meta && flag) flag.textContent = meta.flag;
        if (meta && codeEl) codeEl.textContent = meta.code;
      }
    } catch (e) {}
  }, 50);
};

// První pass až po app rendrování (po loginu)
setTimeout(() => {
  if (window.appekCurrentLang && window.appekCurrentLang !== 'cs') {
    window.translatePage(document.body);
  }
}, 500);
